import json
with open('/home/archon/proj/Cech-Cohomology/.leandag/dag.json') as f:
    d = json.load(f)

# Find isolated nodes
isolated = []
for n in d.get('nodes', []):
    if n.get('isolated', False) or (not n.get('uses', []) and not n.get('used_by', [])):
        isolated.append(n)

print('Checking for explicit isolated flag:')
for n in d.get('nodes', []):
    if n.get('isolated', False):
        print(f'  {n[\"id\"]} type={n.get(\"type\")} chapter={n.get(\"chapter\",\"\")}')

# Also check nodes with zero in and out edges
print()
print('Checking for zero edges (both in and out):')
for n in d.get('nodes', []):
    if not n.get('uses', []) and not n.get('used_by', []) and not n.get('isolated', False):
        print(f'  {n[\"id\"]} type={n.get(\"type\")} chapter={n.get(\"chapter\",\"\")}')
